content.problemStatement:
Chef is planning to setup a secure password for his Codechef account. For a password to be secure the following conditions should be satisfied:



Password must contain at least one lower case letter [a−z][a-z][a−z];




Password must contain at least one upper case letter [A−Z] strictly inside (first or the last character won’t be considered)




Password must contain at least one digit [0−9][0-9][0−9] strictly inside;




Password must contain at least one special character from the set {\{{ '@', '#', '%', '&amp;', '?' }\}} strictly inside;




Password must be at least 101010 characters in length, but it can be longer.



Chef has generated several strings and now wants you to check whether the passwords are secure based on the above criteria. Please help Chef in doing so.

code.C:
#include <stdio.h>
#include <string.h>
#include <stdbool.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0; 
    char buf[210];
    // consume newline after T
    fgets(buf, sizeof(buf), stdin);
    while(T--){
        if(!fgets(buf, sizeof(buf), stdin)) break;
        size_t len = strlen(buf);
        if(len && buf[len-1]=='\n') buf[--len]='\0';
        bool hasLower=false, hasUpperInside=false, hasDigitInside=false, hasSpecialInside=false;
        bool lengthOk = len>=10;
        for(size_t i=0;i<len;i++){
            char c=buf[i];
            if('a'<=c && c<='z') hasLower=true;
            if(i!=0 && i!=len-1){
                if('A'<=c && c<='Z') hasUpperInside=true;
                if('0'<=c && c<='9') hasDigitInside=true;
                if(c=='@' || c=='#' || c=='%' || c=='&' || c=='?') hasSpecialInside=true;
            }
        }
        if(hasLower && hasUpperInside && hasDigitInside && hasSpecialInside && lengthOk) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

