code.Python3:
import sys

def is_secure(s: str) -> bool:
    n = len(s)
    if n < 10:
        return False
    has_lower = any('a' <= ch <= 'z' for ch in s)
    has_upper_inside = any('A' <= s[i] <= 'Z' for i in range(1, n-1))
    has_digit_inside = any('0' <= s[i] <= '9' for i in range(1, n-1))
    specials = {'@', '#', '%', '&', '?'}
    has_special_inside = any(s[i] in specials for i in range(1, n-1))
    return has_lower and has_upper_inside and has_digit_inside and has_special_inside

def main():
    data = sys.stdin.read().splitlines()
    if not data:
        return
    t = int(data[0])
    out = []
    for i in range(1, t+1):
        s = data[i].strip()
        out.append('YES' if is_secure(s) else 'NO')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

