const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const T = parseInt(input[idx++], 10);
let res = [];
const specials = new Set(['@', '#', '%', '&', '?']);
for (let t = 0; t < T; t++) {
  const s = input[idx++] || '';
  const n = s.length;
  let hasLower = false, hasUpperInside = false, hasDigitInside = false, hasSpecialInside = false;
  if (n >= 10) {
    for (let i = 0; i < n; i++) {
      const c = s[i];
      if (c >= 'a' && c <= 'z') hasLower = true;
      if (i !== 0 && i !== n - 1) {
        if (c >= 'A' && c <= 'Z') hasUpperInside = true;
        if (c >= '0' && c <= '9') hasDigitInside = true;
        if (specials.has(c)) hasSpecialInside = true;
      }
    }
  }
  if (hasLower && hasUpperInside && hasDigitInside && hasSpecialInside && n >= 10) res.push('YES');
  else res.push('NO');
}
